from pathlib import Pathimport pandas as pdimport yamldef build_yaml(df):    database = {}    for setting, group in df.groupby("setting"):        entry = {            "band": setting[0],            "reference_wavelength": float(                group["reference_wavelength"]                .iloc[0]            )/1000,            "orders": {}        }        for _, row in group.iterrows():            order = int(row["order"])            entry["orders"][order] = {                "detector1": {                    "min": float(row["detector1_min"])/1000,                    "max": float(row["detector1_max"])/1000,                },                "detector2": {                    "min": float(row["detector2_min"])/1000,                    "max": float(row["detector2_max"])/1000,                },                "detector3": {                    "min": float(row["detector3_min"])/1000,                    "max": float(row["detector3_max"])/1000,                },            }        database[setting] = entry    return databasedef save_yaml(database):    output = Path(        "../src/criresviz/database/crires_settings.yaml"    )    with open(output, "w") as f:        yaml.safe_dump(            database,            f,            sort_keys=False,            indent=2,        )          '''############################################################################################################# MAIN ################################### ###########################################################################'''                 def main():    df = pd.read_csv(        "../resources/extracted/previews/criressettings_tidy.csv"    )    database = build_yaml(df)        save_yaml(database)    print(f"Created database with {len(database)} settings")if __name__ == "__main__":    main()